record.field:
contacts = model.search([('x_studio_subscribe', '=', True)])
mail_template = env['mail.template'].search([('id','=',42)])
for contact in contacts:
    if contact.x_studio_to_notify_properties:
        res = mail_template.send_mail(res_id=contact.id)
        if res: contact.write({'x_studio_last_notification': datetime.datetime.now()}) # Update contact last notification date

if not record.website_ribbon_id.x_studio_is_draft_ribbon and not record.website_ribbon_id.x_studio_is_closed_ribbon:
    if not record.x_studio_ribbon_stage_is_accounted:
        record['x_studio_ribbon_stage_is_accounted'] = True
        record['x_studio_last_notification_update'] = datetime.datetime.now()#.strftime('%Y-%m-%d %H:%M:%S')

if len(record.message_ids) == 1 and not record.x_studio_interested_in :
    properties = env["product.template"].search([])
    for property in properties:
        for reference in property.x_studio_other_ads:
            if reference.x_name in record.message_ids[0].body or reference.x_name in record.message_ids[0].subject or reference.x_name in record.message_ids[0].email_from:
                record["x_studio_interested_in"] = property.id

partner = env['res.partner'].search([('id', '=', env.context.get('active_id'))])
new_lead = { 'name': 'Matchmaking', 'partner_id': partner.id, 'x_studio_interested_in': env.context.get('property_id') }
env['crm.lead'].create(new_lead)
